insert into public.matchjobs_talentos
  (id, nome, emoji, headline, area, senioridade, cidade, modelo, pretensao,
   skills, bio, disponivel)
values
('t-001', 'Marina Albuquerque Sarmento', '🚀', 'Dev front que transforma Figma em pixel perfeito', 'Tecnologia', 'Pleno', 'Recife', 'remoto', 9500, array['React','Next.js','TypeScript','APIs REST']::text[], 'Sou do time que abre o DevTools antes do café. Se a interface travar 100ms, eu percebo — e conserto.', true),
('t-002', 'João Pedro Kowalski', '⚡', 'Dev backend apaixonado por Go', 'Tecnologia', 'Sênior', 'Curitiba', 'remoto', 16000, array['Go','Docker','AWS','SQL','APIs REST']::text[], 'Escrevo serviço que aguenta pico de Black Friday sem suar. Goroutine é meu esporte favorito.', true),
('t-003', 'Larissa Nunes Ferreira', '📱', 'Dev mobile que respira Flutter', 'Tecnologia', 'Júnior', 'Fortaleza', 'hibrido', 4800, array['Flutter','TypeScript','APIs REST','Docker']::text[], 'Publiquei meu primeiro app na Play Store aos 19. Hoje quero construir produto que a minha avó consiga usar.', true),
('t-004', 'Carlos Eduardo Nascimento', '🧠', 'Cientista de dados caçador de padrões', 'Dados', 'Sênior', 'São Paulo', 'remoto', 15000, array['Python','Machine Learning','Spark','BigQuery','Estatística']::text[], 'Desconfio de todo gráfico bonito até ver o p-valor. Modelo que não vai pra produção, pra mim, é hobby.', false),
('t-005', 'Tainá Guajajara', '📊', 'Estagiária de dados viciada em dashboard bonito', 'Dados', 'Estágio', 'Manaus', 'hibrido', 1900, array['SQL','Power BI','Excel Avançado','Python']::text[], 'Aprendi SQL vendo tutorial de madrugada e nunca mais parei. Quero mostrar que dado bom também nasce no Norte.', true),
('t-006', 'Fernanda Yamashita', '🕵️', 'Pentester que pensa como atacante pra defender melhor', 'Segurança', 'Pleno', 'Brasília', 'remoto', 11500, array['Pentest','AppSec','OSINT','Linux','Redes']::text[], 'Meu hobby é achar a porta que esqueceram aberta — e avisar antes que alguém entre. Relatório meu ninguém engaveta.', true),
('t-007', 'Rafael Duarte Boaventura', '🎨', 'Designer de produto obcecado por microinterações', 'Design', 'Pleno', 'Belo Horizonte', 'hibrido', 8000, array['Figma','UI Design','Design System','Prototipagem','Motion']::text[], 'Acredito que um botão bem animado vale mais que mil palavras. Design system pra mim é carinho em escala.', true),
('t-008', 'Bianca Sales do Carmo', '✏️', 'Ilustradora com traço que dá alma pra qualquer marca', 'Design', 'Júnior', 'Salvador', 'remoto', 4200, array['Ilustração','Design Gráfico','Branding','Figma']::text[], 'Desenho desde que me entendo por gente. Minha meta é ver um personagem meu estampado num outdoor da Barroquinha.', true),
('t-009', 'Thiago Munhoz Schneider', '📈', 'Growth que faz CAC chorar e LTV sorrir', 'Marketing', 'Sênior', 'Florianópolis', 'remoto', 11000, array['Growth','Mídia Paga','Analytics','SEO','CRM']::text[], 'Já queimei budget o suficiente pra saber onde não queimar o seu. Teste A/B é minha religião.', true),
('t-010', 'Camila Rocha Andrade', '✍️', 'Copywriter que vende sem parecer anúncio', 'Marketing', 'Pleno', 'Goiânia', 'remoto', 6500, array['Copywriting','Social Media','E-mail Marketing','SEO']::text[], 'Escrevo e-mail que as pessoas abrem por vontade própria. Sim, isso existe — e eu tenho as métricas pra provar.', true),
('t-011', 'Anderson Barros de Jesus', '🎯', 'SDR incansável: 80 ligações por dia sem perder o sorriso', 'Vendas', 'Júnior', 'São Paulo', 'presencial', 3200, array['SDR','Prospecção','CRM','Inside Sales']::text[], 'Vim do telemarketing e descobri que ouvir ''não'' é só aquecimento. Meu pipeline nunca dorme.', false),
('t-012', 'Patrícia Wanderley Falcão', '🤝', 'Executiva de contas que fecha negócio ouvindo mais do que falando', 'Vendas', 'Sênior', 'Rio de Janeiro', 'hibrido', 9500, array['Vendas Consultivas','Negociação','Field Sales','Pós-venda','CRM']::text[], 'Cliente meu renova contrato e ainda me indica pro concorrente dele. Venda boa é a que resolve problema de verdade.', true),
('t-013', 'Gustavo Lorenzetti', '🧭', 'PM que decide com dado e coragem', 'Produto', 'Lead', 'Campinas', 'remoto', 17000, array['Discovery','Roadmap','Métricas','A/B Testing','Gestão de Stakeholders']::text[], 'Já matei mais feature do que lancei — e o produto agradece. Roadmap pra mim é aposta, não promessa.', true),
('t-014', 'Ingrid Falkenberg', '🧩', 'APM curiosa que faz as perguntas que ninguém fez', 'Produto', 'Júnior', 'Blumenau', 'remoto', 5000, array['Discovery','Scrum','Benchmark','UX Writing']::text[], 'Meu superpoder é perguntar ''por quê?'' cinco vezes seguidas sem irritar ninguém. Quase sempre.', true),
('t-015', 'Ricardo Sant''Anna Moreira', '💰', 'Controller que enxerga a empresa pelos números', 'Financeiro', 'Lead', 'São Paulo', 'hibrido', 18000, array['Controladoria','FP&A','Excel Avançado','Auditoria','Valuation']::text[], 'Fecho o mês em D+3 e durmo tranquilo. Planilha minha não tem célula solta nem fórmula quebrada.', true),
('t-016', 'Aline Beltrão Cavalcanti', '🧾', 'Analista fiscal que decifra imposto como ninguém', 'Financeiro', 'Pleno', 'João Pessoa', 'remoto', 6800, array['Contabilidade','Impostos','Excel Avançado','Tesouraria']::text[], 'Reforma tributária não me assusta, me anima. Já economizei uns bons milhões em autuação evitada.', true),
('t-017', 'Marcos Vinícius Peixoto', '⚙️', 'Analista de operações que corta retrabalho pela raiz', 'Operações', 'Pleno', 'Uberlândia', 'presencial', 5500, array['Processos','Gestão de Projetos','Qualidade','Excel Avançado']::text[], 'Se um processo tem 10 passos, eu acho um jeito de fazer em 6. Fluxograma é meu segundo idioma.', true),
('t-018', 'Juliana Okamoto Prado', '💜', 'Tech recruiter que trata candidato como cliente', 'RH & Pessoas', 'Pleno', 'Natal', 'remoto', 7000, array['Recrutamento','Employer Branding','Cultura','People Analytics']::text[], 'Devolutiva em 48h é o mínimo — candidato fantasma, jamais. Contrato por potencial, não só por currículo.', true),
('t-019', 'Rosângela Batista dos Anjos', '🩺', 'Enfermeira que ama plantão noturno', 'Saúde', 'Pleno', 'Belém', 'presencial', 5800, array['Enfermagem','Urgência e Emergência','Atendimento Clínico','Prontuário Eletrônico']::text[], 'Doze anos de plantão e ainda me emociono com alta de paciente. Na madrugada, sou eu quem segura a onda.', false),
('t-020', 'Felipe Iorio Cardoso', '💪', 'Fisioterapeuta que devolve movimento e autoestima', 'Saúde', 'Júnior', 'Niterói', 'presencial', 3800, array['Fisioterapia','Atendimento Clínico','Prontuário Eletrônico','Urgência e Emergência']::text[], 'Vi meu pai reaprender a andar depois de um AVC e decidi minha profissão ali. Cada sessão é uma pequena vitória.', true),
('t-021', 'Sônia Maria Quaresma', '📚', 'Professora que transforma aula em conversa boa', 'Educação', 'Sênior', 'São Luís', 'presencial', 5200, array['Docência','Pedagogia','Coordenação Pedagógica','Reforço Escolar']::text[], 'Vinte anos de sala de aula e nenhuma vontade de parar. Aluno meu aprende porque quer, não porque cai na prova.', true),
('t-022', 'Diego Ferraz Lobato', '🎓', 'Designer instrucional que faz EAD prender atenção', 'Educação', 'Pleno', 'Palmas', 'remoto', 5500, array['Design Instrucional','Tutoria EAD','Docência','Pedagogia']::text[], 'Curso online não precisa ser slide lido em voz alta. Eu desenho trilha que o aluno termina — e recomenda.', true),
('t-023', 'Helena Steinbach', '🏗️', 'Engenheira civil que entrega obra no prazo e no orçamento', 'Engenharia', 'Sênior', 'Porto Alegre', 'presencial', 13500, array['Gestão de Obras','Orçamento de Obras','AutoCAD','Segurança do Trabalho']::text[], 'Canteiro de obra é meu escritório favorito. Cronograma comigo não estoura — quem me conhece sabe.', true),
('t-024', 'Wesley Damasceno', '🔩', 'Projetista mecânico apaixonado por SolidWorks', 'Engenharia', 'Pleno', 'Joinville', 'hibrido', 7800, array['SolidWorks','Projetos Mecânicos','AutoCAD','Manutenção Industrial']::text[], 'Desmontava brinquedo pra ver como funcionava; hoje projeto a peça antes de ela existir. Tolerância apertada não me assusta.', true),
('t-025', 'Renata Bulhões Sampaio', '⚖️', 'Advogada trabalhista que traduz juridiquês pra gente normal', 'Jurídico', 'Pleno', 'Maceió', 'hibrido', 8000, array['Trabalhista','Contencioso','Peticionamento','Contratos']::text[], 'Petição minha o juiz lê sem bocejar. Acredito que direito bom é o que o cliente entende na primeira explicação.', true),
('t-026', 'Otávio Guimarães Rezende', '🚚', 'Analista de logística que sonha com rota otimizada', 'Logística', 'Pleno', 'Guarulhos', 'presencial', 5800, array['Roteirização','WMS','Transporte','Estoque','Supply Chain']::text[], 'Reduzi 18% do custo de frete só reorganizando janela de coleta. Mapa aberto e planilha do lado: sou eu.', true),
('t-027', 'Ícaro Nolasco Pires', '🛎️', 'Recepcionista bilíngue que faz hóspede se sentir em casa', 'Turismo & Eventos', 'Júnior', 'Gramado', 'presencial', 2800, array['Recepção','Hotelaria','Reservas','Inglês']::text[], 'Já virei madrugada resolvendo overbooking com sorriso no rosto. Hóspede que volta e lembra meu nome é meu troféu.', false),
('t-028', 'Luana Figueiredo Matos', '🧁', 'Confeiteira que faz brigadeiro virar arte', 'Gastronomia', 'Pleno', 'Pelotas', 'presencial', 3800, array['Confeitaria','Panificação','Ficha Técnica','Boas Práticas']::text[], 'Cresci na cidade do doce e levo isso a sério: minha ficha técnica é cirúrgica e meu croissant, escandaloso.', true),
('t-029', 'Jorge Baptista Neto', '👨‍🍳', 'Cozinheiro de mão cheia criado na cozinha da avó', 'Gastronomia', 'Sênior', 'Vitória', 'presencial', 6000, array['Cozinha Quente','Gestão de Cozinha','Ficha Técnica','Boas Práticas','Atendimento de Salão']::text[], 'Comando praça quente há 15 anos sem perder a paciência nem o tempero. Minha moqueca já fez gente chorar — de alegria.', true),
('t-030', 'Késia Rodrigues Lima', '🛍️', 'Vendedora que bate meta com atendimento de gente', 'Varejo & Atendimento', 'Júnior', 'Teresina', 'presencial', 2400, array['Vendas de Loja','Caixa','Atendimento ao Cliente','Estoque de Loja']::text[], 'Cliente entra pra olhar e sai com sacola e sorriso. Decoro o nome de quem volta — e todo mundo volta.', true),
('t-031', 'Ronaldo Xavier Brito', '🏬', 'Gerente de loja que faz o time vestir a camisa', 'Varejo & Atendimento', 'Lead', 'Ribeirão Preto', 'presencial', 5500, array['Gestão de Loja','Visual Merchandising','Vendas de Loja','Atendimento ao Cliente']::text[], 'Comecei como estoquista e hoje toco loja com 22 pessoas. Vitrine bem montada, equipe motivada: o resto é consequência.', true),
('t-032', 'Josué Ferreira do Vale', '🔌', 'Eletricista predial que não deixa ninguém no escuro', 'Construção & Manutenção', 'Sênior', 'Contagem', 'presencial', 4800, array['Elétrica Predial','Manutenção Predial','Leitura de Projeto','Hidráulica']::text[], 'São 18 anos de quadro de força sem um acidente. NR-10 em dia e serviço limpo: caixa que eu fecho não dá dor de cabeça.', true),
('t-033', 'Elisângela Prates Moura', '🪚', 'Marceneira que transforma MDF em móvel dos sonhos', 'Construção & Manutenção', 'Pleno', 'Caxias do Sul', 'presencial', 3800, array['Marcenaria','Pintura','Leitura de Projeto','Manutenção Predial']::text[], 'Aprendi o ofício com meu pai e hoje sou eu quem assina os móveis planejados. Encaixe perfeito não é sorte, é capricho.', false),
('t-034', 'Cleiton Almeida Braga', '🏭', 'Técnico de produção fanático por 5S e café coado', 'Indústria & Produção', 'Pleno', 'Sorocaba', 'presencial', 4200, array['Operação de Máquinas','CLP','Controle de Qualidade','Lean Manufacturing','5S']::text[], 'Linha parada me tira o sono, então aprendi CLP pra resolver na hora. Meu setor é o mais organizado da fábrica — com orgulho.', true),
('t-035', 'Maria Rita Carvalho Dantas', '🌾', 'Agrônoma que fala a língua do sertão e a do drone', 'Agro & Meio Ambiente', 'Sênior', 'Petrolina', 'hibrido', 9500, array['Agronomia','Agricultura de Precisão','Irrigação','Gestão Rural','Licenciamento Ambiental']::text[], 'Cresci no meio da manga e da uva do Vale do São Francisco. Uso mapa de satélite de manhã e conversa de porteira à tarde.', true),
('t-036', 'Wallace dos Reis Militão', '💈', 'Barbeiro raiz com agenda lotada e papo em dia', 'Beleza & Bem-estar', 'Pleno', 'Duque de Caxias', 'presencial', 3500, array['Barbearia','Cabelo','Estética Facial','Gestão de Salão']::text[], 'Cliente meu marca horário de novo antes de levantar da cadeira. Degradê na régua e freguesia que virou família.', true)
on conflict (id) do update set
  nome = excluded.nome, emoji = excluded.emoji, headline = excluded.headline,
  area = excluded.area, senioridade = excluded.senioridade,
  cidade = excluded.cidade, modelo = excluded.modelo,
  pretensao = excluded.pretensao, skills = excluded.skills,
  bio = excluded.bio, disponivel = excluded.disponivel;
